@startuml
entity "note" {
  id : int <<PK>>
  job_id : int <<FK>>
  text : string
  created : datetime
}

entity "job" {
  id : int <<PK>>
  status : enum [scheduled|active|invoicing|to priced|completed]
  created : date
  client_name : varchar(256)
  address : varchar(1024)
  client_contact_number : char(38)
}

' Relationships from original diagram are preserved but commented out since they don't match new requirements
'relation note ||--o{ job : "" 

@enduml
